window.KJV1769_STRONG_BOOKS["Jas"] = {"osis":"Jas","book":"야고보서","verses":{"1:1":{"text":"James, a servant of God and of the Lord Jesus Christ, to the twelve tribes which are scattered abroad, greeting.","words":[["G2385","James",0,5],["G1401","a servant",7,16],["G2316","of God",17,23],["G2532","and",24,27],["G2962","of the Lord",28,39],["G2424","Jesus",40,45],["G5547","Christ",46,52],["G1427","to the twelve",54,67],["G5443","tribes",68,74],["G1722","which",75,80],["G1290","are scattered abroad",81,101],["G5463","greeting",103,111]]},"1:2":{"text":"My brethren, count it all joy when ye fall into divers temptations;","words":[["G3450","My",0,2],["G0080","brethren",3,11],["G2233","count it",13,21],["G3956","all",22,25],["G5479","joy",26,29],["G3752","when",30,34],["G4045","ye fall",35,42],["G4164","into divers",43,54],["G3986","temptations",55,66]]},"1:3":{"text":"Knowing this, that the trying of your faith worketh patience.","words":[["G1097","Knowing",0,7],["G3754","this, that",8,18],["G1383","the trying",19,29],["G5216","of your",30,37],["G4102","faith",38,43],["G2716","worketh",44,51],["G5281","patience",52,60]]},"1:4":{"text":"But let patience have her perfect work, that ye may be perfect and entire, wanting nothing.","words":[["G1161","But",0,3],["G2192","let",4,7],["G5281","patience",8,16],["G2192","have",17,21],["G5046","her perfect",22,33],["G2041","work",34,38],["G2443","that",40,44],["G5600","ye may be",45,54],["G5046","perfect",55,62],["G2532","and",63,66],["G3648","entire",67,73],["G3007","wanting",75,82],["G1722","nothing",83,90],["G3367","nothing",83,90]]},"1:5":{"text":"If any of you lack wisdom, let him ask of God, that giveth to all men liberally, and upbraideth not; and it shall be given him.","words":[["G1161","",-1,-1],["G1536","If any",0,6],["G5216","of you",7,13],["G3007","lack",14,18],["G4678","wisdom",19,25],["G0154","let him ask",27,38],["G3844","of",39,41],["G2316","God",42,45],["G1325","that giveth",47,58],["G3956","to all",59,65],["G0574","men liberally",66,79],["G2532","and",81,84],["G3679","upbraideth",85,95],["G3361","not",96,99],["G2532","and",101,104],["G1325","it shall be given",105,122],["G0846","him",123,126]]},"1:6":{"text":"But let him ask in faith, nothing wavering. For he that wavereth is like a wave of the sea driven with the wind and tossed.","words":[["G1161","But",0,3],["G0154","let him ask",4,15],["G1722","in",16,18],["G4102","faith",19,24],["G3367","nothing",26,33],["G1252","wavering",34,42],["G1063","For",44,47],["G1252","he that wavereth",48,64],["G1503","is like",65,72],["G2830","a wave",73,79],["G2281","of the sea",80,90],["G0416","driven with the wind",91,111],["G2532","and",112,115],["G4494","tossed",116,122]]},"1:7":{"text":"For let not that man think that he shall receive any thing of the Lord.","words":[["G1063","For",0,3],["G3633","let",4,7],["G3361","not",8,11],["G1565","that",12,16],["G0444","man",17,20],["G3633","think",21,26],["G3754","that",27,31],["G2983","he shall receive",32,48],["G5100","any thing",49,58],["G3844","of",59,61],["G2962","the Lord",62,70]]},"1:8":{"text":"A double minded man is unstable in all his ways.","words":[["G1374","A double minded",0,15],["G0435","man",16,19],["G0182","is unstable",20,31],["G1722","in",32,34],["G3956","all",35,38],["G0846","his",39,42],["G3598","ways",43,47]]},"1:9":{"text":"Let the brother of low degree rejoice in that he is exalted:","words":[["G1161","",-1,-1],["G2744","Let",0,3],["G0080","the brother",4,15],["G5011","of low degree",16,29],["G2744","rejoice",30,37],["G1722","in",38,40],["G0846","that he",41,48],["G5311","is exalted",49,59]]},"1:10":{"text":"But the rich, in that he is made low: because as the flower of the grass he shall pass away.","words":[["G1161","But",0,3],["G4145","the rich",4,12],["G1722","in",14,16],["G0846","that he",17,24],["G5014","is made low",25,36],["G3754","because",38,45],["G5613","as",46,48],["G0438","the flower",49,59],["G5528","of the grass",60,72],["G3928","he shall pass away",73,91]]},"1:11":{"text":"For the sun is no sooner risen with a burning heat, but it withereth the grass, and the flower thereof falleth, and the grace of the fashion of it perisheth: so also shall the rich man fade away in his ways.","words":[["G1063","For",0,3],["G2246","the sun",4,11],["G0393","is no sooner risen",12,30],["G4862","with",31,35],["G2742","a burning heat",36,50],["G2532","but",52,55],["G3583","it withereth",56,68],["G5528","the grass",69,78],["G2532","and",80,83],["G0438","the flower",84,94],["G0846","thereof",95,102],["G1601","falleth",103,110],["G2532","and",112,115],["G2143","the grace",116,125],["G4383","of the fashion",126,140],["G0846","of it",141,146],["G0622","perisheth",147,156],["G3779","so",158,160],["G2532","also",161,165],["G3133","shall",166,171],["G4145","the rich man",172,184],["G3133","fade away",185,194],["G1722","in",195,197],["G0846","his",198,201],["G4197","ways",202,206]]},"1:12":{"text":"Blessed is the man that endureth temptation: for when he is tried, he shall receive the crown of life, which the Lord hath promised to them that love him.","words":[["G3107","Blessed",0,7],["G0435","is the man",8,18],["G3739","that",19,23],["G5278","endureth",24,32],["G3986","temptation",33,43],["G3754","for",45,48],["G1384","when he is tried",49,65],["G1096","when he is tried",49,65],["G2983","he shall receive",67,83],["G4735","the crown",84,93],["G2222","of life",94,101],["G3739","which",103,108],["G2962","the Lord",109,117],["G1861","hath promised",118,131],["G0025","to them that love",132,149],["G0846","him",150,153]]},"1:13":{"text":"Let no man say when he is tempted, I am tempted of God: for God cannot be tempted with evil, neither tempteth he any man:","words":[["G3004","Let",0,3],["G3367","no man",4,10],["G3004","say",11,14],["G3985","when he is tempted",15,33],["G3754","",-1,-1],["G3985","I am tempted",35,47],["G0575","of",48,50],["G2316","God",51,54],["G1063","for",56,59],["G2316","God",60,63],["G0551","cannot be tempted",64,81],["G2076","cannot be tempted",64,81],["G2556","with evil",82,91],["G1161","neither",93,100],["G3985","tempteth",101,109],["G0846","he",110,112],["G3985","he",110,112],["G3762","any man",113,120]]},"1:14":{"text":"But every man is tempted, when he is drawn away of his own lust, and enticed.","words":[["G1161","But",0,3],["G1538","every man",4,13],["G3985","is tempted",14,24],["G1828","when he is drawn away",26,47],["G5259","of",48,50],["G2398","his own",51,58],["G1939","lust",59,63],["G2532","and",65,68],["G1185","enticed",69,76]]},"1:15":{"text":"Then when lust hath conceived, it bringeth forth sin: and sin, when it is finished, bringeth forth death.","words":[["G1534","Then",0,4],["G1939","when lust",5,14],["G4815","hath conceived",15,29],["G5088","it bringeth forth",31,48],["G0266","sin",49,52],["G1161","and",54,57],["G0266","sin",58,61],["G0658","when it is finished",63,82],["G0616","bringeth forth",84,98],["G2288","death",99,104]]},"1:16":{"text":"Do not err, my beloved brethren.","words":[["G4105","Do",0,2],["G3361","not",3,6],["G4105","err",7,10],["G3450","my",12,14],["G0027","beloved",15,22],["G0080","brethren",23,31]]},"1:17":{"text":"Every good gift and every perfect gift is from above, and cometh down from the Father of lights, with whom is no variableness, neither shadow of turning.","words":[["G3956","Every",0,5],["G0018","good",6,10],["G1394","gift",11,15],["G2532","and",16,19],["G3956","every",20,25],["G5046","perfect",26,33],["G1434","gift",34,38],["G2076","is",39,41],["G0509","from above",42,52],["G2597","and cometh down",54,69],["G0575","from",70,74],["G3962","the Father",75,85],["G5457","of lights",86,95],["G3844","with",97,101],["G3739","whom",102,106],["G1762","is",107,109],["G3756","no",110,112],["G3883","variableness",113,125],["G2228","neither",127,134],["G0644","shadow",135,141],["G5157","of turning",142,152]]},"1:18":{"text":"Of his own will begat he us with the word of truth, that we should be a kind of firstfruits of his creatures.","words":[["G1014","Of his own will",0,15],["G0616","begat he",16,24],["G2248","us",25,27],["G3056","with the word",28,41],["G0225","of truth",42,50],["G1519","that",52,56],["G2248","we",57,59],["G1511","should be",60,69],["G5100","a kind",70,76],["G0536","of firstfruits",77,91],["G0846","of his",92,98],["G2938","creatures",99,108]]},"1:19":{"text":"Wherefore, my beloved brethren, let every man be swift to hear, slow to speak, slow to wrath:","words":[["G5620","Wherefore",0,9],["G3450","my",11,13],["G0027","beloved",14,21],["G0080","brethren",22,30],["G2077","let",32,35],["G3956","every",36,41],["G0444","man",42,45],["G2077","be",46,48],["G5036","swift",49,54],["G1519","to",55,57],["G0191","hear",58,62],["G1021","slow",64,68],["G1519","to",69,71],["G2980","speak",72,77],["G1021","slow",79,83],["G1519","to",84,86],["G3709","wrath",87,92]]},"1:20":{"text":"For the wrath of man worketh not the righteousness of God.","words":[["G1063","For",0,3],["G3709","the wrath",4,13],["G0435","of man",14,20],["G2716","worketh",21,28],["G3756","not",29,32],["G1343","the righteousness",33,50],["G2316","of God",51,57]]},"1:21":{"text":"Wherefore lay apart all filthiness and superfluity of naughtiness, and receive with meekness the engrafted word, which is able to save your souls.","words":[["G1352","Wherefore",0,9],["G0659","lay apart",10,19],["G3956","all",20,23],["G4507","filthiness",24,34],["G2532","and",35,38],["G4050","superfluity",39,50],["G2549","of naughtiness",51,65],["G1209","and receive",67,78],["G1722","with",79,83],["G4240","meekness",84,92],["G1721","the engrafted",93,106],["G3056","word",107,111],["G3588","which",113,118],["G1410","is able",119,126],["G4982","to save",127,134],["G5216","your",135,139],["G5590","souls",140,145]]},"1:22":{"text":"But be ye doers of the word, and not hearers only, deceiving your own selves.","words":[["G1161","But",0,3],["G1096","be ye",4,9],["G4163","doers",10,15],["G3056","of the word",16,27],["G2532","and",29,32],["G3361","not",33,36],["G0202","hearers",37,44],["G3440","only",45,49],["G3884","deceiving",51,60],["G1438","your own selves",61,76]]},"1:23":{"text":"For if any be a hearer of the word, and not a doer, he is like unto a man beholding his natural face in a glass:","words":[["G3754","For",0,3],["G1536","if any",4,10],["G2076","be",11,13],["G0202","a hearer",14,22],["G3056","of the word",23,34],["G2532","and",36,39],["G3756","not",40,43],["G4163","a doer",44,50],["G3778","he",52,54],["G1503","is like",55,62],["G0435","unto a man",63,73],["G2657","beholding",74,83],["G0846","his",84,87],["G1078","natural",88,95],["G4383","face",96,100],["G1722","in",101,103],["G2072","a glass",104,111]]},"1:24":{"text":"For he beholdeth himself, and goeth his way, and straightway forgetteth what manner of man he was.","words":[["G1063","For",0,3],["G2657","he beholdeth",4,16],["G1438","himself",17,24],["G2532","and",26,29],["G0565","goeth his way",30,43],["G2532","and",45,48],["G2112","straightway",49,60],["G1950","forgetteth",61,71],["G3697","what manner of man",72,90],["G2258","he was",91,97]]},"1:25":{"text":"But whoso looketh into the perfect law of liberty, and continueth therein, he being not a forgetful hearer, but a doer of the work, this man shall be blessed in his deed.","words":[["G1161","But",0,3],["G3879","whoso looketh",4,17],["G1519","into",18,22],["G5046","the perfect",23,34],["G3551","law",35,38],["G1657","of liberty",39,49],["G2532","and",51,54],["G3887","continueth",55,65],["G3778","therein, he",66,77],["G1096","being",78,83],["G3756","not",84,87],["G1953","a forgetful",88,99],["G0202","hearer",100,106],["G0235","but",108,111],["G4163","a doer",112,118],["G2041","of the work",119,130],["G3778","this man",132,140],["G2071","shall be",141,149],["G3107","blessed",150,157],["G1722","in",158,160],["G0846","his",161,164],["G4162","deed",165,169]]},"1:26":{"text":"If any man among you seem to be religious, and bridleth not his tongue, but deceiveth his own heart, this man's religion is vain.","words":[["G1536","If any man",0,10],["G1722","among",11,16],["G5213","you",17,20],["G1380","seem",21,25],["G1511","to be",26,31],["G2357","religious",32,41],["G5468","and bridleth",43,55],["G3361","not",56,59],["G0846","his",60,63],["G1100","tongue",64,70],["G0235","but",72,75],["G0538","deceiveth",76,85],["G0846","his own",86,93],["G2588","heart",94,99],["G5127","this man's",101,111],["G2356","religion",112,120],["G3152","is vain",121,128]]},"1:27":{"text":"Pure religion and undefiled before God and the Father is this, To visit the fatherless and widows in their affliction, and to keep himself unspotted from the world.","words":[["G2513","Pure",0,4],["G2356","religion",5,13],["G2532","and",14,17],["G0283","undefiled",18,27],["G3844","before",28,34],["G2316","God",35,38],["G2532","and",39,42],["G3962","the Father",43,53],["G2076","is",54,56],["G3778","this",57,61],["G1980","To visit",63,71],["G3737","the fatherless",72,86],["G2532","and",87,90],["G5503","widows",91,97],["G1722","in",98,100],["G0846","their",101,106],["G2347","affliction",107,117],["G5083","and to keep",119,130],["G1438","himself",131,138],["G0784","unspotted",139,148],["G0575","from",149,153],["G2889","the world",154,163]]},"2:1":{"text":"My brethren, have not the faith of our Lord Jesus Christ, the Lord of glory, with respect of persons.","words":[["G3450","My",0,2],["G0080","brethren",3,11],["G2192","have",13,17],["G3361","not",18,21],["G4102","the faith",22,31],["G2257","of our",32,38],["G2962","Lord",39,43],["G2424","Jesus",44,49],["G5547","Christ",50,56],["G1391","the Lord of glory",58,75],["G1722","with",77,81],["G4382","respect of persons",82,100]]},"2:2":{"text":"For if there come unto your assembly a man with a gold ring, in goodly apparel, and there come in also a poor man in vile raiment;","words":[["G1063","For",0,3],["G1437","if",4,6],["G1525","there come",7,17],["G1519","unto",18,22],["G5216","your",23,27],["G4864","assembly",28,36],["G0435","a man",37,42],["G5554","with a gold ring",43,59],["G1722","in",61,63],["G2986","goodly",64,70],["G2066","apparel",71,78],["G1161","and",80,83],["G1525","there come in",84,97],["G2532","also",98,102],["G4434","a poor man",103,113],["G1722","in",114,116],["G4508","vile",117,121],["G2066","raiment",122,129]]},"2:3":{"text":"And ye have respect to him that weareth the gay clothing, and say unto him, Sit thou here in a good place; and say to the poor, Stand thou there, or sit here under my footstool:","words":[["G2532","And",0,3],["G1914","ye have respect",4,19],["G1909","to",20,22],["G5409","him that weareth",23,39],["G2986","the gay",40,47],["G2066","clothing",48,56],["G2532","and",58,61],["G2036","say",62,65],["G0846","unto him",66,74],["G2521","Sit",76,79],["G4771","thou",80,84],["G5602","here",85,89],["G2573","in a good place",90,105],["G2532","and",107,110],["G2036","say",111,114],["G4434","to the poor",115,126],["G2476","Stand",128,133],["G4771","thou",134,138],["G1563","there",139,144],["G2228","or",146,148],["G2521","sit",149,152],["G5602","here",153,157],["G5259","under",158,163],["G3450","my",164,166],["G5286","footstool",167,176]]},"2:4":{"text":"Are ye not then partial in yourselves, and are become judges of evil thoughts?","words":[["G1252","Are ye",0,6],["G3756","not",7,10],["G2532","then",11,15],["G1252","partial",16,23],["G1722","in",24,26],["G1438","yourselves",27,37],["G2532","and",39,42],["G1096","are become",43,53],["G2923","judges",54,60],["G4190","of evil",61,68],["G1261","thoughts",69,77]]},"2:5":{"text":"Hearken, my beloved brethren, Hath not God chosen the poor of this world rich in faith, and heirs of the kingdom which he hath promised to them that love him?","words":[["G0191","Hearken",0,7],["G3450","my",9,11],["G0027","beloved",12,19],["G0080","brethren",20,28],["G1586","Hath",30,34],["G3756","not",35,38],["G2316","God",39,42],["G1586","chosen",43,49],["G4434","the poor",50,58],["G5127","of this",59,66],["G2889","world",67,72],["G4145","rich",73,77],["G1722","in",78,80],["G4102","faith",81,86],["G2532","and",88,91],["G2818","heirs",92,97],["G0932","of the kingdom",98,112],["G3739","which",113,118],["G1861","he hath promised",119,135],["G0025","to them that love",136,153],["G0846","him",154,157]]},"2:6":{"text":"But ye have despised the poor. Do not rich men oppress you, and draw you before the judgment seats?","words":[["G1161","But",0,3],["G5210","ye",4,6],["G0818","have despised",7,20],["G4434","the poor",21,29],["G2616","Do",31,33],["G3756","not",34,37],["G4145","rich men",38,46],["G2616","oppress",47,54],["G5216","you",55,58],["G2532","and",60,63],["G0846","draw",64,68],["G1670","draw",64,68],["G5209","you",69,72],["G1519","before",73,79],["G2922","the judgment seats",80,98]]},"2:7":{"text":"Do not they blaspheme that worthy name by the which ye are called?","words":[["G0987","Do",0,2],["G3756","not",3,6],["G0846","they",7,11],["G0987","blaspheme",12,21],["G2570","that worthy",22,33],["G3686","name",34,38],["G1909","by",39,41],["G5209","the which ye",42,54],["G1941","are called",55,65]]},"2:8":{"text":"If ye fulfil the royal law according to the scripture, Thou shalt love thy neighbour as thyself, ye do well:","words":[["G1487","If",0,2],["G3305","If",0,2],["G5055","ye fulfil",3,12],["G0937","the royal",13,22],["G3551","law",23,26],["G2596","according to",27,39],["G1124","the scripture",40,53],["G0025","Thou shalt love",55,70],["G4675","thy",71,74],["G4139","neighbour",75,84],["G5613","as",85,87],["G4572","thyself",88,95],["G4160","ye do",97,102],["G2573","well",103,107]]},"2:9":{"text":"But if ye have respect to persons, ye commit sin, and are convinced of the law as transgressors.","words":[["G1161","But",0,3],["G1487","if",4,6],["G4380","ye have respect to persons",7,33],["G2038","ye commit",35,44],["G0266","sin",45,48],["G1651","and are convinced",50,67],["G5259","of",68,70],["G3551","the law",71,78],["G5613","as",79,81],["G3848","transgressors",82,95]]},"2:10":{"text":"For whosoever shall keep the whole law, and yet offend in one point, he is guilty of all.","words":[["G1063","For",0,3],["G3748","whosoever",4,13],["G5083","shall keep",14,24],["G3650","the whole",25,34],["G3551","law",35,38],["G1161","and yet",40,47],["G4417","offend",48,54],["G1722","in",55,57],["G1520","one",58,61],["G1096","point, he is",62,74],["G1777","guilty",75,81],["G3956","of all",82,88]]},"2:11":{"text":"For he that said, Do not commit adultery, said also, Do not kill. Now if thou commit no adultery, yet if thou kill, thou art become a transgressor of the law.","words":[["G1063","For",0,3],["G2036","he that said",4,16],["G3431","Do",18,20],["G3361","not",21,24],["G3431","commit adultery",25,40],["G2036","said",42,46],["G2532","also",47,51],["G5407","Do",53,55],["G3361","not",56,59],["G5407","kill",60,64],["G1161","Now",66,69],["G1487","if",70,72],["G3431","thou commit",73,84],["G3756","no",85,87],["G3431","adultery",88,96],["G1161","yet if",98,104],["G5407","thou kill",105,114],["G1096","thou art become",116,131],["G3848","a transgressor",132,146],["G3551","of the law",147,157]]},"2:12":{"text":"So speak ye, and so do, as they that shall be judged by the law of liberty.","words":[["G3779","So",0,2],["G2980","speak ye",3,11],["G2532","and",13,16],["G3779","so",17,19],["G4160","do",20,22],["G5613","as",24,26],["G3195","they that shall be",27,45],["G2919","judged",46,52],["G1223","by",53,55],["G3551","the law",56,63],["G1657","of liberty",64,74]]},"2:13":{"text":"For he shall have judgment without mercy, that hath shewed no mercy; and mercy rejoiceth against judgment.","words":[["G1063","For",0,3],["G2920","he shall have judgment",4,26],["G0448","without mercy",27,40],["G4160","that hath shewed",42,58],["G3361","no",59,61],["G1656","mercy",62,67],["G2532","and",69,72],["G1656","mercy",73,78],["G2620","rejoiceth against",79,96],["G2920","judgment",97,105]]},"2:14":{"text":"What doth it profit, my brethren, though a man say he hath faith, and have not works? can faith save him?","words":[["G5101","What",0,4],["G3786","doth it profit",5,19],["G3450","my",21,23],["G0080","brethren",24,32],["G1437","though",34,40],["G5100","a man",41,46],["G3004","say",47,50],["G2192","he hath",51,58],["G4102","faith",59,64],["G1161","and",66,69],["G2192","have",70,74],["G3361","not",75,78],["G2041","works",79,84],["G1410","can",86,89],["G3361","can",86,89],["G4102","faith",90,95],["G4982","save",96,100],["G0846","him",101,104]]},"2:15":{"text":"If a brother or sister be naked, and destitute of daily food,","words":[["G1437","If",0,2],["G1161","If",0,2],["G0080","a brother",3,12],["G2228","or",13,15],["G0079","sister",16,22],["G5225","be",23,25],["G1131","naked",26,31],["G2532","and",33,36],["G3007","destitute",37,46],["G5600","destitute",37,46],["G2184","of daily",47,55],["G5160","food",56,60]]},"2:16":{"text":"And one of you say unto them, Depart in peace, be ye warmed and filled; notwithstanding ye give them not those things which are needful to the body; what doth it profit?","words":[["G1161","And",0,3],["G5100","one",4,7],["G1537","of",8,10],["G5216","you",11,14],["G2036","say",15,18],["G0846","unto them",19,28],["G5217","Depart",30,36],["G1722","in",37,39],["G1515","peace",40,45],["G2328","be ye warmed",47,59],["G2532","and",60,63],["G5526","filled",64,70],["G1161","notwithstanding",72,87],["G1325","ye give",88,95],["G0846","them",96,100],["G3361","not",101,104],["G2006","those things which are needful",105,135],["G4983","to the body",136,147],["G5101","what",149,153],["G3786","doth it profit",154,168]]},"2:17":{"text":"Even so faith, if it hath not works, is dead, being alone.","words":[["G2532","Even",0,4],["G3779","so",5,7],["G4102","faith",8,13],["G3362","if",15,17],["G2192","it hath",18,25],["G3362","not",26,29],["G2041","works",30,35],["G2076","is",37,39],["G3498","dead",40,44],["G2596","being alone",46,57],["G1438","being alone",46,57]]},"2:18":{"text":"Yea, a man may say, Thou hast faith, and I have works: shew me thy faith without thy works, and I will shew thee my faith by my works.","words":[["G0235","Yea",0,3],["G5100","a man",5,10],["G2046","may say",11,18],["G4771","Thou",20,24],["G2192","hast",25,29],["G4102","faith",30,35],["G2504","and I",37,42],["G2192","have",43,47],["G2041","works",48,53],["G1166","shew",55,59],["G3427","me",60,62],["G4675","thy",63,66],["G4102","faith",67,72],["G1537","without",73,80],["G4675","thy",81,84],["G2041","works",85,90],["G2504","and I",92,97],["G1166","will shew",98,107],["G4671","thee",108,112],["G3450","my",113,115],["G4102","faith",116,121],["G1537","by",122,124],["G3450","my",125,127],["G2041","works",128,133]]},"2:19":{"text":"Thou believest that there is one God; thou doest well: the devils also believe, and tremble.","words":[["G4771","Thou",0,4],["G4100","believest",5,14],["G3754","that",15,19],["G2076","there is",20,28],["G1520","one",29,32],["G2316","God",33,36],["G4160","thou doest",38,48],["G2573","well",49,53],["G1140","the devils",55,65],["G2532","also",66,70],["G4100","believe",71,78],["G2532","and",80,83],["G5425","tremble",84,91]]},"2:20":{"text":"But wilt thou know, O vain man, that faith without works is dead?","words":[["G1161","But",0,3],["G2309","wilt",4,8],["G1097","thou know",9,18],["G5599","O",20,21],["G2756","vain",22,26],["G0444","man",27,30],["G3754","that",32,36],["G4102","faith",37,42],["G5565","without",43,50],["G2041","works",51,56],["G2076","is",57,59],["G3498","dead",60,64]]},"2:21":{"text":"Was not Abraham our father justified by works, when he had offered Isaac his son upon the altar?","words":[["G1344","Was",0,3],["G3756","not",4,7],["G0011","Abraham",8,15],["G2257","our",16,19],["G3962","father",20,26],["G1344","justified",27,36],["G1537","by",37,39],["G2041","works",40,45],["G0399","when he had offered",47,66],["G2464","Isaac",67,72],["G0846","his",73,76],["G5207","son",77,80],["G1909","upon",81,85],["G2379","the altar",86,95]]},"2:22":{"text":"Seest thou how faith wrought with his works, and by works was faith made perfect?","words":[["G0991","Seest thou",0,10],["G3754","how",11,14],["G4102","faith",15,20],["G4903","wrought",21,28],["G0846","with his",29,37],["G2041","works",38,43],["G2532","and",45,48],["G1537","by",49,51],["G2041","works",52,57],["G5048","was",58,61],["G4102","faith",62,67],["G5048","made perfect",68,80]]},"2:23":{"text":"And the scripture was fulfilled which saith, Abraham believed God, and it was imputed unto him for righteousness: and he was called the Friend of God.","words":[["G2532","And",0,3],["G1124","the scripture",4,17],["G4137","was fulfilled",18,31],["G3004","which saith",32,43],["G1161","",-1,-1],["G0011","Abraham",45,52],["G4100","believed",53,61],["G2316","God",62,65],["G2532","and",67,70],["G3049","it was imputed",71,85],["G0846","unto him",86,94],["G1519","for",95,98],["G1343","righteousness",99,112],["G2532","and",114,117],["G2564","he was called",118,131],["G5384","the Friend",132,142],["G2316","of God",143,149]]},"2:24":{"text":"Ye see then how that by works a man is justified, and not by faith only.","words":[["G3708","Ye see",0,6],["G5106","then",7,11],["G3754","how that",12,20],["G1537","by",21,23],["G2041","works",24,29],["G0444","a man",30,35],["G1344","is justified",36,48],["G2532","and",50,53],["G3756","not",54,57],["G1537","by",58,60],["G4102","faith",61,66],["G3440","only",67,71]]},"2:25":{"text":"Likewise also was not Rahab the harlot justified by works, when she had received the messengers, and had sent them out another way?","words":[["G3668","Likewise",0,8],["G1161","Likewise",0,8],["G2532","also",9,13],["G1344","was",14,17],["G3756","not",18,21],["G4460","Rahab",22,27],["G4204","the harlot",28,38],["G1344","justified",39,48],["G1537","by",49,51],["G2041","works",52,57],["G5264","when she had received",59,80],["G0032","the messengers",81,95],["G2532","and",97,100],["G1544","had sent them out",101,118],["G2087","another",119,126],["G3598","way",127,130]]},"2:26":{"text":"For as the body without the spirit is dead, so faith without works is dead also.","words":[["G1063","For",0,3],["G5618","as",4,6],["G4983","the body",7,15],["G5565","without",16,23],["G4151","the spirit",24,34],["G2076","is",35,37],["G3498","dead",38,42],["G3779","so",44,46],["G4102","faith",47,52],["G5565","without",53,60],["G2041","works",61,66],["G2076","is",67,69],["G3498","dead",70,74],["G2532","also",75,79]]},"3:1":{"text":"My brethren, be not many masters, knowing that we shall receive the greater condemnation.","words":[["G3450","My",0,2],["G0080","brethren",3,11],["G1096","be",13,15],["G3361","not",16,19],["G4183","many",20,24],["G1320","masters",25,32],["G1492","knowing",34,41],["G3754","that",42,46],["G2983","we shall receive",47,63],["G3187","the greater",64,75],["G2917","condemnation",76,88]]},"3:2":{"text":"For in many things we offend all. If any man offend not in word, the same is a perfect man, and able also to bridle the whole body.","words":[["G1063","For",0,3],["G4183","in many things",4,18],["G4417","we offend",19,28],["G0537","all",29,32],["G1536","If any man",34,44],["G4417","offend",45,51],["G3756","not",52,55],["G1722","in",56,58],["G3056","word",59,63],["G3778","the same",65,73],["G5046","is a perfect",74,86],["G0435","man",87,90],["G1415","and able",92,100],["G2532","also",101,105],["G5468","to bridle",106,115],["G3650","the whole",116,125],["G4983","body",126,130]]},"3:3":{"text":"Behold, we put bits in the horses' mouths, that they may obey us; and we turn about their whole body.","words":[["G2400","Behold",0,6],["G0906","we put",8,14],["G5469","bits",15,19],["G1519","in",20,22],["G2462","the horses'",23,34],["G4750","mouths",35,41],["G4314","that",43,47],["G0846","they",48,52],["G3982","may obey",53,61],["G2254","us",62,64],["G2532","and",66,69],["G3329","we turn about",70,83],["G0846","their",84,89],["G3650","whole",90,95],["G4983","body",96,100]]},"3:4":{"text":"Behold also the ships, which though they be so great, and are driven of fierce winds, yet are they turned about with a very small helm, whithersoever the governor listeth.","words":[["G2400","Behold",0,6],["G2532","also",7,11],["G4143","the ships",12,21],["G5607","which though they be",23,43],["G5082","so great",44,52],["G2532","and",54,57],["G1643","are driven",58,68],["G5259","of",69,71],["G4642","fierce",72,78],["G0417","winds",79,84],["G3329","yet are they turned about",86,111],["G5259","with",112,116],["G1646","a very small",117,129],["G4079","helm",130,134],["G3699","whithersoever",136,149],["G0302","whithersoever",136,149],["G2116","the governor",150,162],["G3730","listeth",163,170],["G1014","listeth",163,170]]},"3:5":{"text":"Even so the tongue is a little member, and boasteth great things. Behold, how great a matter a little fire kindleth!","words":[["G2532","Even",0,4],["G3779","so",5,7],["G1100","the tongue",8,18],["G2076","is",19,21],["G3398","a little",22,30],["G3196","member",31,37],["G2532","and",39,42],["G3166","boasteth great things",43,64],["G2400","Behold",66,72],["G2245","how great",74,83],["G5208","a matter",84,92],["G3641","a little",93,101],["G4442","fire",102,106],["G0381","kindleth",107,115]]},"3:6":{"text":"And the tongue is a fire, a world of iniquity: so is the tongue among our members, that it defileth the whole body, and setteth on fire the course of nature; and it is set on fire of hell.","words":[["G2532","And",0,3],["G1100","the tongue",4,14],["G4442","is a fire",15,24],["G2889","a world",26,33],["G0093","of iniquity",34,45],["G3779","so",47,49],["G2525","is",50,52],["G1100","the tongue",53,63],["G1722","among",64,69],["G2257","our",70,73],["G3196","members",74,81],["G4695","that it defileth",83,99],["G3650","the whole",100,109],["G4983","body",110,114],["G2532","and",116,119],["G5394","setteth on fire",120,135],["G5164","the course",136,146],["G1078","of nature",147,156],["G2532","and",158,161],["G5394","it is set on fire",162,179],["G5259","of",180,182],["G1067","hell",183,187]]},"3:7":{"text":"For every kind of beasts, and of birds, and of serpents, and of things in the sea, is tamed, and hath been tamed of mankind:","words":[["G1063","For",0,3],["G3956","every",4,9],["G5449","kind",10,14],["G2342","of beasts",15,24],["G5037","and",26,29],["G2532","and",26,29],["G4071","of birds",30,38],["G5037","and",40,43],["G2062","of serpents",44,55],["G2532","and",57,60],["G1724","of things in the sea",61,81],["G1150","is tamed",83,91],["G2532","and",93,96],["G1150","hath been tamed",97,112],["G5449","of mankind",113,123],["G0442","of mankind",113,123]]},"3:8":{"text":"But the tongue can no man tame; it is an unruly evil, full of deadly poison.","words":[["G1161","But",0,3],["G1100","the tongue",4,14],["G1410","can",15,18],["G3762","no",19,21],["G0444","man",22,25],["G1150","tame",26,30],["G0183","it is an unruly",32,47],["G2556","evil",48,52],["G3324","full",54,58],["G2287","of deadly",59,68],["G2447","poison",69,75]]},"3:9":{"text":"Therewith bless we God, even the Father; and therewith curse we men, which are made after the similitude of God.","words":[["G1722","Therewith",0,9],["G0846","Therewith",0,9],["G2127","bless we",10,18],["G2316","God",19,22],["G2532","even",24,28],["G3962","the Father",29,39],["G2532","and",41,44],["G1722","therewith",45,54],["G0846","therewith",45,54],["G2672","curse we",55,63],["G0444","men",64,67],["G3588","which",69,74],["G1096","are made",75,83],["G2596","after",84,89],["G3669","the similitude",90,104],["G2316","of God",105,111]]},"3:10":{"text":"Out of the same mouth proceedeth blessing and cursing. My brethren, these things ought not so to be.","words":[["G1537","Out of",0,6],["G0846","the same",7,15],["G4750","mouth",16,21],["G1831","proceedeth",22,32],["G2129","blessing",33,41],["G2532","and",42,45],["G2671","cursing",46,53],["G3450","My",55,57],["G0080","brethren",58,66],["G5023","these things",68,80],["G5534","ought",81,86],["G3756","not",87,90],["G3779","so",91,93],["G1096","to be",94,99]]},"3:11":{"text":"Doth a fountain send forth at the same place sweet water and bitter?","words":[["G3385","Doth",0,4],["G4077","a fountain",5,15],["G1032","send forth",16,26],["G1537","at",27,29],["G0846","the same",30,38],["G3692","place",39,44],["G1099","sweet",45,50],["G2532","water and",51,60],["G4089","bitter",61,67]]},"3:12":{"text":"Can the fig tree, my brethren, bear olive berries? either a vine, figs? so can no fountain both yield salt water and fresh.","words":[["G3361","Can",0,3],["G1410","Can",0,3],["G4808","the fig tree",4,16],["G3450","my",18,20],["G0080","brethren",21,29],["G4160","bear",31,35],["G1636","olive berries",36,49],["G2228","either",51,57],["G0288","a vine",58,64],["G4810","figs",66,70],["G3779","so",72,74],["G3762","can no",75,81],["G4077","fountain",82,90],["G4160","both yield",91,101],["G0252","salt",102,106],["G5204","water",107,112],["G2532","and",113,116],["G1099","fresh",117,122]]},"3:13":{"text":"Who is a wise man and endued with knowledge among you? let him shew out of a good conversation his works with meekness of wisdom.","words":[["G5101","Who",0,3],["G4680","is a wise man",4,17],["G2532","and",18,21],["G1990","endued with knowledge",22,43],["G1722","among",44,49],["G5213","you",50,53],["G1166","let him shew",55,67],["G1537","out of",68,74],["G2570","a good",75,81],["G0391","conversation",82,94],["G0846","his",95,98],["G2041","works",99,104],["G1722","with",105,109],["G4240","meekness",110,118],["G4678","of wisdom",119,128]]},"3:14":{"text":"But if ye have bitter envying and strife in your hearts, glory not, and lie not against the truth.","words":[["G1161","But",0,3],["G1487","if",4,6],["G2192","ye have",7,14],["G4089","bitter",15,21],["G2205","envying",22,29],["G2532","and",30,33],["G2052","strife",34,40],["G1722","in",41,43],["G5216","your",44,48],["G2588","hearts",49,55],["G2620","glory",57,62],["G3361","not",63,66],["G2532","and",68,71],["G5574","lie not",72,79],["G2596","against",80,87],["G0225","the truth",88,97]]},"3:15":{"text":"This wisdom descendeth not from above, but is earthly, sensual, devilish.","words":[["G3778","This",0,4],["G4678","wisdom",5,11],["G2076","descendeth",12,22],["G2718","descendeth",12,22],["G3756","not",23,26],["G0509","from above",27,37],["G0235","but",39,42],["G1919","is earthly",43,53],["G5591","sensual",55,62],["G1141","devilish",64,72]]},"3:16":{"text":"For where envying and strife is, there is confusion and every evil work.","words":[["G1063","For",0,3],["G3699","where",4,9],["G2205","envying",10,17],["G2532","and",18,21],["G2052","strife",22,28],["G1563","is, there",29,38],["G0181","is confusion",39,51],["G2532","and",52,55],["G3956","every",56,61],["G5337","evil",62,66],["G4229","work",67,71]]},"3:17":{"text":"But the wisdom that is from above is first pure, then peaceable, gentle, and easy to be intreated, full of mercy and good fruits, without partiality, and without hypocrisy.","words":[["G1161","But",0,3],["G4678","the wisdom",4,14],["G0509","that is from above",15,33],["G2076","is",34,36],["G4412","first",37,42],["G3303","pure",43,47],["G0053","pure",43,47],["G1899","then",49,53],["G1516","peaceable",54,63],["G1933","gentle",65,71],["G2138","and easy to be intreated",73,97],["G3324","full",99,103],["G1656","of mercy",104,112],["G2532","and",113,116],["G0018","good",117,121],["G2590","fruits",122,128],["G0087","without partiality",130,148],["G2532","and",150,153],["G0505","without hypocrisy",154,171]]},"3:18":{"text":"And the fruit of righteousness is sown in peace of them that make peace.","words":[["G1161","And",0,3],["G2590","the fruit",4,13],["G1343","of righteousness",14,30],["G4687","is sown",31,38],["G1722","in",39,41],["G1515","peace",42,47],["G4160","of them that make",48,65],["G1515","peace",66,71]]},"4:1":{"text":"From whence come wars and fightings among you? come they not hence, even of your lusts that war in your members?","words":[["G4159","From whence",0,11],["G4171","come wars",12,21],["G2532","and",22,25],["G3163","fightings",26,35],["G1722","among",36,41],["G5213","you",42,45],["G3756","come they not",47,60],["G1782","hence",61,66],["G1537","even of",68,75],["G5216","your",76,80],["G2237","lusts",81,86],["G4754","that war",87,95],["G1722","in",96,98],["G5216","your",99,103],["G3196","members",104,111]]},"4:2":{"text":"Ye lust, and have not: ye kill, and desire to have, and cannot obtain: ye fight and war, yet ye have not, because ye ask not.","words":[["G1937","Ye lust",0,7],["G2532","and",9,12],["G2192","have",13,17],["G3756","not",18,21],["G5407","ye kill",23,30],["G2532","and",32,35],["G2206","desire to have",36,50],["G2532","and",52,55],["G3756","cannot",56,62],["G1410","cannot",56,62],["G2013","obtain",63,69],["G3164","ye fight",71,79],["G2532","and",80,83],["G4170","war",84,87],["G1161","yet",89,92],["G2192","ye have",93,100],["G3756","not",101,104],["G1223","because",106,113],["G5209","ye",114,116],["G0154","ask",117,120],["G3361","not",121,124]]},"4:3":{"text":"Ye ask, and receive not, because ye ask amiss, that ye may consume it upon your lusts.","words":[["G0154","Ye ask",0,6],["G2532","and",8,11],["G2983","receive",12,19],["G3756","not",20,23],["G1360","because",25,32],["G0154","ye ask",33,39],["G2560","amiss",40,45],["G2443","that",47,51],["G1159","ye may consume",52,66],["G1722","it upon",67,74],["G5216","your",75,79],["G2237","lusts",80,85]]},"4:4":{"text":"Ye adulterers and adulteresses, know ye not that the friendship of the world is enmity with God? whosoever therefore will be a friend of the world is the enemy of God.","words":[["G3432","Ye adulterers",0,13],["G2532","and",14,17],["G3428","adulteresses",18,30],["G1492","know ye",32,39],["G3756","not",40,43],["G3754","that",44,48],["G5373","the friendship",49,63],["G2889","of the world",64,76],["G2076","is",77,79],["G2189","enmity",80,86],["G2316","with God",87,95],["G3739","whosoever",97,106],["G0302","whosoever",97,106],["G3767","therefore",107,116],["G1511","will be",117,124],["G1014","will be",117,124],["G5384","a friend",125,133],["G2889","of the world",134,146],["G2525","is",147,149],["G2190","the enemy",150,159],["G2316","of God",160,166]]},"4:5":{"text":"Do ye think that the scripture saith in vain, The spirit that dwelleth in us lusteth to envy?","words":[["G2228","",-1,-1],["G1380","Do ye think",0,11],["G3754","that",12,16],["G1124","the scripture",17,30],["G3004","saith",31,36],["G2761","in vain",37,44],["G4151","The spirit",46,56],["G3739","that",57,61],["G2730","dwelleth",62,70],["G1722","in",71,73],["G2254","us",74,76],["G1971","lusteth",77,84],["G4314","to",85,87],["G5355","envy",88,92]]},"4:6":{"text":"But he giveth more grace. Wherefore he saith, God resisteth the proud, but giveth grace unto the humble.","words":[["G1161","But",0,3],["G1325","he giveth",4,13],["G3187","more",14,18],["G5485","grace",19,24],["G1352","Wherefore",26,35],["G3004","he saith",36,44],["G2316","God",46,49],["G0498","resisteth",50,59],["G5244","the proud",60,69],["G1161","but",71,74],["G1325","giveth",75,81],["G5485","grace",82,87],["G5011","unto the humble",88,103]]},"4:7":{"text":"Submit yourselves therefore to God. Resist the devil, and he will flee from you.","words":[["G5293","Submit yourselves",0,17],["G3767","therefore",18,27],["G2316","to God",28,34],["G0436","Resist",36,42],["G1228","the devil",43,52],["G2532","and",54,57],["G5343","he will flee",58,70],["G0575","from",71,75],["G5216","you",76,79]]},"4:8":{"text":"Draw nigh to God, and he will draw nigh to you. Cleanse your hands, ye sinners; and purify your hearts, ye double minded.","words":[["G1448","Draw nigh",0,9],["G2316","to God",10,16],["G2532","and",18,21],["G1448","he will draw nigh",22,39],["G5213","to you",40,46],["G2511","Cleanse",48,55],["G5495","your hands",56,66],["G0268","ye sinners",68,78],["G2532","and",80,83],["G0048","purify",84,90],["G2588","your hearts",91,102],["G1374","ye double minded",104,120]]},"4:9":{"text":"Be afflicted, and mourn, and weep: let your laughter be turned to mourning, and your joy to heaviness.","words":[["G5003","Be afflicted",0,12],["G2532","and",14,17],["G3996","mourn",18,23],["G2532","and",25,28],["G2799","weep",29,33],["G5216","let your",35,43],["G1071","laughter",44,52],["G3344","be turned",53,62],["G1519","to",63,65],["G3997","mourning",66,74],["G2532","and",76,79],["G5479","your joy",80,88],["G1519","to",89,91],["G2726","heaviness",92,101]]},"4:10":{"text":"Humble yourselves in the sight of the Lord, and he shall lift you up.","words":[["G5013","Humble yourselves",0,17],["G1799","in the sight",18,30],["G2962","of the Lord",31,42],["G2532","and",44,47],["G5312","he shall lift",48,61],["G5209","you",62,65],["G5312","up",66,68]]},"4:11":{"text":"Speak not evil one of another, brethren. He that speaketh evil of his brother, and judgeth his brother, speaketh evil of the law, and judgeth the law: but if thou judge the law, thou art not a doer of the law, but a judge.","words":[["G2635","Speak",0,5],["G3361","not",6,9],["G2635","evil",10,14],["G0240","one of another",15,29],["G0080","brethren",31,39],["G2635","He that speaketh evil",41,62],["G0080","of his brother",63,77],["G2532","and",79,82],["G2919","judgeth",83,90],["G0846","his",91,94],["G0080","brother",95,102],["G2635","speaketh evil",104,117],["G3551","of the law",118,128],["G2532","and",130,133],["G2919","judgeth",134,141],["G3551","the law",142,149],["G1161","but",151,154],["G1487","if",155,157],["G2919","thou judge",158,168],["G3551","the law",169,176],["G1488","thou art",178,186],["G3756","not",187,190],["G4163","a doer",191,197],["G3551","of the law",198,208],["G0235","but",210,213],["G2923","a judge",214,221]]},"4:12":{"text":"There is one lawgiver, who is able to save and to destroy: who art thou that judgest another?","words":[["G2076","There is",0,8],["G1520","one",9,12],["G3550","lawgiver",13,21],["G3588","who",23,26],["G1410","is able",27,34],["G4982","to save",35,42],["G2532","and",43,46],["G0622","to destroy",47,57],["G5101","who",59,62],["G1488","art",63,66],["G4771","thou",67,71],["G3739","that",72,76],["G2919","judgest",77,84],["G2087","another",85,92]]},"4:13":{"text":"Go to now, ye that say, To day or to morrow we will go into such a city, and continue there a year, and buy and sell, and get gain:","words":[["G0033","Go to",0,5],["G3568","now",6,9],["G3004","ye that say",11,22],["G4594","To day",24,30],["G2532","or",31,33],["G0839","to morrow",34,43],["G4198","we will go",44,54],["G1519","into",55,59],["G3592","such",60,64],["G4172","a city",65,71],["G2532","and",73,76],["G4160","continue",77,85],["G4160","continue",77,85],["G1563","there",86,91],["G1520","a",92,93],["G1763","year",94,98],["G2532","and",100,103],["G1710","buy and sell",104,116],["G1710","buy and sell",104,116],["G2532","and",118,121],["G2770","get gain",122,130],["G2770","get gain",122,130]]},"4:14":{"text":"Whereas ye know not what shall be on the morrow. For what is your life? It is even a vapour, that appeareth for a little time, and then vanisheth away.","words":[["G3748","Whereas",0,7],["G1987","ye know",8,15],["G3756","not",16,19],["G3588","what",20,24],["G0839","shall be on the morrow",25,47],["G1063","For",49,52],["G4169","what",53,57],["G5216","is your",58,65],["G2222","life",66,70],["G2076","It is",72,77],["G1063","even",78,82],["G0822","a vapour",83,91],["G4314","that",93,97],["G5316","appeareth for",98,111],["G3641","a little time",112,125],["G1161","and",127,130],["G1899","then",131,135],["G0853","vanisheth away",136,150]]},"4:15":{"text":"For that ye ought to say, If the Lord will, we shall live, and do this, or that.","words":[["G0473","For that",0,8],["G5209","ye",9,11],["G3004","ought to say",12,24],["G1437","If",26,28],["G2962","the Lord",29,37],["G2309","will",38,42],["G2532","",-1,-1],["G2198","we shall live",44,57],["G2198","we shall live",44,57],["G2532","and",59,62],["G4160","do",63,65],["G4160","do",63,65],["G5124","this",66,70],["G2228","or",72,74],["G1565","that",75,79]]},"4:16":{"text":"But now ye rejoice in your boastings: all such rejoicing is evil.","words":[["G1161","But",0,3],["G3568","now",4,7],["G2744","ye rejoice",8,18],["G1722","in",19,21],["G5216","your",22,26],["G0212","boastings",27,36],["G3956","all",38,41],["G5108","such",42,46],["G2746","rejoicing",47,56],["G2076","is",57,59],["G4190","evil",60,64]]},"4:17":{"text":"Therefore to him that knoweth to do good, and doeth it not, to him it is sin.","words":[["G3767","Therefore",0,9],["G1492","to him that knoweth",10,29],["G4160","to do",30,35],["G2570","good",36,40],["G2532","and",42,45],["G4160","doeth",46,51],["G3361","it not",52,58],["G0846","to him",60,66],["G2076","it is",67,72],["G0266","sin",73,76]]},"5:1":{"text":"Go to now, ye rich men, weep and howl for your miseries that shall come upon you.","words":[["G0033","Go to",0,5],["G3568","now",6,9],["G4145","ye rich men",11,22],["G2799","weep",24,28],["G3649","and howl",29,37],["G1909","for",38,41],["G5216","your",42,46],["G5004","miseries",47,55],["G1904","that shall come upon",56,76]]},"5:2":{"text":"Your riches are corrupted, and your garments are motheaten.","words":[["G5216","Your",0,4],["G4149","riches",5,11],["G4595","are corrupted",12,25],["G2532","and",27,30],["G5216","your",31,35],["G2440","garments",36,44],["G1096","are",45,48],["G4598","motheaten",49,58]]},"5:3":{"text":"Your gold and silver is cankered; and the rust of them shall be a witness against you, and shall eat your flesh as it were fire. Ye have heaped treasure together for the last days.","words":[["G5216","Your",0,4],["G5557","gold",5,9],["G2532","and",10,13],["G0696","silver",14,20],["G2728","is cankered",21,32],["G2532","and",34,37],["G2447","the rust",38,46],["G0846","of them",47,54],["G2071","shall be",55,63],["G3142","a witness",64,73],["G1519","against",74,81],["G5213","you",82,85],["G2532","and",87,90],["G5315","shall eat",91,100],["G5216","your",101,105],["G4561","flesh",106,111],["G5613","as it were",112,122],["G4442","fire",123,127],["G2343","Ye have heaped treasure together",129,161],["G1722","for",162,165],["G2078","the last",166,174],["G2250","days",175,179]]},"5:4":{"text":"Behold, the hire of the labourers who have reaped down your fields, which is of you kept back by fraud, crieth: and the cries of them which have reaped are entered into the ears of the Lord of sabaoth.","words":[["G2400","Behold",0,6],["G3408","the hire",8,16],["G2040","of the labourers",17,33],["G3588","who",34,37],["G0270","have reaped down",38,54],["G5216","your",55,59],["G5561","fields",60,66],["G3588","which",68,73],["G0575","is of",74,79],["G5216","you",80,83],["G0650","kept back by fraud",84,102],["G2896","crieth",104,110],["G2532","and",112,115],["G0995","the cries",116,125],["G2325","of them which have reaped",126,151],["G1525","are entered",152,163],["G1519","into",164,168],["G3775","the ears",169,177],["G2962","of the Lord",178,189],["G4519","of sabaoth",190,200]]},"5:5":{"text":"Ye have lived in pleasure on the earth, and been wanton; ye have nourished your hearts, as in a day of slaughter.","words":[["G5171","Ye have lived in pleasure",0,25],["G1909","on",26,28],["G1093","the earth",29,38],["G2532","and",40,43],["G4684","been wanton",44,55],["G5142","ye have nourished",57,74],["G5216","your",75,79],["G2588","hearts",80,86],["G5613","as",88,90],["G1722","in",91,93],["G2250","a day",94,99],["G4967","of slaughter",100,112]]},"5:6":{"text":"Ye have condemned and killed the just; and he doth not resist you.","words":[["G2613","Ye have condemned",0,17],["G5407","and killed",18,28],["G1342","the just",29,37],["G0498","and he doth",39,50],["G3756","not",51,54],["G0498","resist",55,61],["G5213","you",62,65]]},"5:7":{"text":"Be patient therefore, brethren, unto the coming of the Lord. Behold, the husbandman waiteth for the precious fruit of the earth, and hath long patience for it, until he receive the early and latter rain.","words":[["G3114","Be patient",0,10],["G3767","therefore",11,20],["G0080","brethren",22,30],["G2193","unto",32,36],["G3952","the coming",37,47],["G2962","of the Lord",48,59],["G2400","Behold",61,67],["G1092","the husbandman",69,83],["G1551","waiteth",84,91],["G5093","for the precious",92,108],["G2590","fruit",109,114],["G1093","of the earth",115,127],["G3114","and hath long patience",129,151],["G1909","for",152,155],["G0846","it",156,158],["G2193","until",160,165],["G0302","until",160,165],["G2983","he receive",166,176],["G4406","the early",177,186],["G2532","and",187,190],["G3797","latter",191,197],["G5205","rain",198,202]]},"5:8":{"text":"Be ye also patient; stablish your hearts: for the coming of the Lord draweth nigh.","words":[["G3114","Be",0,2],["G5210","ye",3,5],["G2532","also",6,10],["G3114","patient",11,18],["G4741","stablish",20,28],["G5216","your",29,33],["G2588","hearts",34,40],["G3754","for",42,45],["G3952","the coming",46,56],["G2962","of the Lord",57,68],["G1448","draweth nigh",69,81]]},"5:9":{"text":"Grudge not one against another, brethren, lest ye be condemned: behold, the judge standeth before the door.","words":[["G4727","Grudge",0,6],["G3361","not",7,10],["G2596","one against another",11,30],["G0240","one against another",11,30],["G0080","brethren",32,40],["G3363","lest",42,46],["G2632","ye be condemned",47,62],["G2400","behold",64,70],["G2923","the judge",72,81],["G2476","standeth",82,90],["G4253","before",91,97],["G2374","the door",98,106]]},"5:10":{"text":"Take, my brethren, the prophets, who have spoken in the name of the Lord, for an example of suffering affliction, and of patience.","words":[["G2983","Take",0,4],["G3450","my",6,8],["G0080","brethren",9,17],["G4396","the prophets",19,31],["G3739","who",33,36],["G2980","have spoken",37,48],["G3686","in the name",49,60],["G2962","of the Lord",61,72],["G5262","for an example",74,88],["G2552","of suffering affliction",89,112],["G2532","and",114,117],["G3115","of patience",118,129]]},"5:11":{"text":"Behold, we count them happy which endure. Ye have heard of the patience of Job, and have seen the end of the Lord; that the Lord is very pitiful, and of tender mercy.","words":[["G2400","Behold",0,6],["G3106","we count them happy",8,27],["G5278","which endure",28,40],["G0191","Ye have heard",42,55],["G5281","of the patience",56,71],["G2492","of Job",72,78],["G2532","and",80,83],["G1492","have seen",84,93],["G5056","the end",94,101],["G2962","of the Lord",102,113],["G3754","that",115,119],["G2962","the Lord",120,128],["G2076","is",129,131],["G4184","very pitiful",132,144],["G2532","and",146,149],["G3629","of tender mercy",150,165]]},"5:12":{"text":"But above all things, my brethren, swear not, neither by heaven, neither by the earth, neither by any other oath: but let your yea be yea; and your nay, nay; lest ye fall into condemnation.","words":[["G1161","But",0,3],["G4253","above",4,9],["G3956","all things",10,20],["G3450","my",22,24],["G0080","brethren",25,33],["G3660","swear",35,40],["G3361","not",41,44],["G3383","neither",46,53],["G3772","by heaven",54,63],["G3383","neither",65,72],["G1093","by the earth",73,85],["G3383","neither",87,94],["G5100","by any",95,101],["G0243","other",102,107],["G3727","oath",108,112],["G1161","but",114,117],["G2277","let",118,121],["G5216","your",122,126],["G3483","yea",127,130],["G2277","be",131,133],["G3483","yea",134,137],["G2532","and",139,142],["G3756","your nay",143,151],["G3756","nay",153,156],["G3363","lest",158,162],["G4098","ye fall",163,170],["G1519","into",171,175],["G5272","condemnation",176,188]]},"5:13":{"text":"Is any among you afflicted? let him pray. Is any merry? let him sing psalms.","words":[["G2553","Is",0,2],["G5100","any",3,6],["G1722","among",7,12],["G5213","you",13,16],["G2553","afflicted",17,26],["G4336","let him pray",28,40],["G2114","Is",42,44],["G5100","any",45,48],["G2114","merry",49,54],["G5567","let him sing psalms",56,75]]},"5:14":{"text":"Is any sick among you? let him call for the elders of the church; and let them pray over him, anointing him with oil in the name of the Lord:","words":[["G0770","Is",0,2],["G5100","any",3,6],["G0770","sick",7,11],["G1722","among",12,17],["G5213","you",18,21],["G4341","let him call",23,35],["G4245","for the elders",36,50],["G1577","of the church",51,64],["G2532","and",66,69],["G4336","let them pray",70,83],["G1909","over",84,88],["G0846","him",89,92],["G0218","anointing",94,103],["G0846","him",104,107],["G1637","with oil",108,116],["G1722","in",117,119],["G3686","the name",120,128],["G2962","of the Lord",129,140]]},"5:15":{"text":"And the prayer of faith shall save the sick, and the Lord shall raise him up; and if he have committed sins, they shall be forgiven him.","words":[["G2532","And",0,3],["G2171","the prayer",4,14],["G4102","of faith",15,23],["G4982","shall save",24,34],["G2577","the sick",35,43],["G2532","and",45,48],["G2962","the Lord",49,57],["G1453","shall raise",58,69],["G0846","him",70,73],["G1453","up",74,76],["G2579","and if",78,84],["G5600","he have",85,92],["G4160","committed",93,102],["G0266","sins",103,107],["G0863","they shall be forgiven",109,131],["G0846","him",132,135]]},"5:16":{"text":"Confess your faults one to another, and pray one for another, that ye may be healed. The effectual fervent prayer of a righteous man availeth much.","words":[["G1843","Confess",0,7],["G3900","your faults",8,19],["G0240","one to another",20,34],["G2532","and",36,39],["G2172","pray",40,44],["G0240","one",45,48],["G5228","for",49,52],["G0240","another",53,60],["G3704","that",62,66],["G2390","ye may be healed",67,83],["G1754","The effectual fervent",85,106],["G1162","prayer",107,113],["G1342","of a righteous man",114,132],["G2480","availeth",133,141],["G4183","much",142,146]]},"5:17":{"text":"Elias was a man subject to like passions as we are, and he prayed earnestly that it might not rain: and it rained not on the earth by the space of three years and six months.","words":[["G2243","Elias",0,5],["G2258","was",6,9],["G0444","a man",10,15],["G3663","subject to like passions as",16,43],["G2254","we are",44,50],["G2532","and",52,55],["G4336","he prayed",56,65],["G4335","earnestly",66,75],["G1026","that it might",76,89],["G3361","not",90,93],["G1026","rain",94,98],["G2532","and",100,103],["G1026","it rained",104,113],["G3756","not",114,117],["G1909","on",118,120],["G1093","the earth",121,130],["G5140","by the space of three",131,152],["G1763","years",153,158],["G2532","and",159,162],["G1803","six",163,166],["G3376","months",167,173]]},"5:18":{"text":"And he prayed again, and the heaven gave rain, and the earth brought forth her fruit.","words":[["G2532","And",0,3],["G4336","he prayed",4,13],["G3825","again",14,19],["G2532","and",21,24],["G3772","the heaven",25,35],["G1325","gave",36,40],["G5205","rain",41,45],["G2532","and",47,50],["G1093","the earth",51,60],["G0985","brought forth",61,74],["G0846","her",75,78],["G2590","fruit",79,84]]},"5:19":{"text":"Brethren, if any of you do err from the truth, and one convert him;","words":[["G0080","Brethren",0,8],["G1437","if",10,12],["G5100","any",13,16],["G1722","of",17,19],["G5213","you",20,23],["G4105","do err",24,30],["G0575","from",31,35],["G0225","the truth",36,45],["G2532","and",47,50],["G5100","one",51,54],["G1994","convert",55,62],["G0846","him",63,66]]},"5:20":{"text":"Let him know, that he which converteth the sinner from the error of his way shall save a soul from death, and shall hide a multitude of sins.","words":[["G1097","Let",0,3],["G0846","him",4,7],["G1097","know",8,12],["G3754","that",14,18],["G1994","he which converteth",19,38],["G0268","the sinner",39,49],["G1537","from",50,54],["G4106","the error",55,64],["G0846","of his",65,71],["G3598","way",72,75],["G4982","shall save",76,86],["G5590","a soul",87,93],["G1537","from",94,98],["G2288","death",99,104],["G2532","and",106,109],["G2572","shall hide",110,120],["G4128","a multitude",121,132],["G0266","of sins",133,140]]}}};
